import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you know if you are overweight?", a: "For adults, BMI is commonly used as a screening tool. A BMI from 25 to 29.9 is classified as overweight, while 30 or higher is classified as obesity." },
  { q: "What BMI is considered overweight?", a: "A BMI of 25.0 to 29.9 is generally considered overweight for adults." },
  { q: "How much weight do you need to lose to stop being overweight?", a: "This calculator compares your current weight with the top of the healthy BMI range for your height and estimates the weight difference." },
  { q: "What are the health risks of being overweight?", a: "Excess weight can increase risk for high blood pressure, type 2 diabetes, sleep apnea, joint strain, heart disease, and other conditions." },
  { q: "What is the fastest healthy way to lose weight?", a: "A steady calorie deficit, higher protein intake, regular activity, sleep, and medical guidance when needed are safer than crash dieting." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const bmi = (weight: number, height: number) => weight / (height * height) * 703;
const weightAtBmi = (targetBmi: number, height: number) => targetBmi * height * height / 703;
function classify(value: number) {
  if (value < 18.5) return "Underweight";
  if (value < 25) return "Healthy weight";
  if (value < 30) return "Overweight";
  if (value < 35) return "Obesity class I";
  if (value < 40) return "Obesity class II";
  return "Obesity class III";
}

export default function OverweightCalculator() {
  const [age, setAge] = useState(35);
  const [gender, setGender] = useState("Female");
  const [height, setHeight] = useState(69);
  const [weight, setWeight] = useState(185);
  const result = useMemo(() => {
    const value = bmi(weight, height);
    const healthyLow = weightAtBmi(18.5, height);
    const healthyHigh = weightAtBmi(24.9, height);
    return { value, status: classify(value), healthyLow, healthyHigh, toLose: Math.max(0, weight - healthyHigh) };
  }, [height, weight]);
  const sampleHeight = 69;
  const rows = [["Under 18.5", "Underweight", "Possible nutrition risk", 0], ["18.5-24.9", "Healthy weight", "Lower average risk", 0], ["25-29.9", "Overweight", "Increased risk", weightAtBmi(25, sampleHeight) - weightAtBmi(24.9, sampleHeight)], ["30-34.9", "Obesity class I", "High risk", weightAtBmi(30, sampleHeight) - weightAtBmi(24.9, sampleHeight)], ["35-39.9", "Obesity class II", "Very high risk", weightAtBmi(35, sampleHeight) - weightAtBmi(24.9, sampleHeight)], ["40 plus", "Obesity class III", "Extremely high risk", weightAtBmi(40, sampleHeight) - weightAtBmi(24.9, sampleHeight)]];

  return (
    <>
      <SEOHead title="Free Overweight Calculator Online - Calculate If You Are Overweight and How Much to Lose | CalcHive" description="Free online overweight calculator. Calculate your BMI, find out if you are overweight and see exactly how much weight you need to lose to reach a healthy weight instantly. 100% free, no signup required." canonical="/overweight-calculator" keywords="free overweight calculator, am I overweight calculator free online, BMI overweight calculator free, how much weight to lose calculator free, overweight BMI calculator free" category="Health Calculators" breadcrumbName="Free Overweight Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Overweight Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate BMI, overweight status, healthy weight range, and estimated weight to lose.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Female</option><option>Male</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Your BMI</p><p className="text-5xl sm:text-6xl font-black text-white">{result.value.toFixed(1)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Status</p><p className="text-lg font-extrabold">{result.status}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Healthy range</p><p className="text-lg font-extrabold">{result.healthyLow.toFixed(0)}-{result.healthyHigh.toFixed(0)} lb</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">To reach healthy BMI</p><p className="text-lg font-extrabold">{result.toLose.toFixed(1)} lb</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate If You Are Overweight for Free</h2><p className="text-muted-foreground leading-relaxed">BMI divides body weight by height squared and places the result into standard adult weight categories.</p><h2 className="text-2xl font-bold">How Much Weight Do You Need to Lose to Be Healthy</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Overweight and Obesity Classification by BMI</caption><thead className="bg-muted/60"><tr>{["BMI Range", "Classification", "Health Risk", "Weight to Lose for Healthy BMI on 5ft 9in Person"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0] as string}><td className="py-2.5 px-3">{r[0]}</td><td className="py-2.5 px-3">{r[1]}</td><td className="py-2.5 px-3">{r[2]}</td><td className="py-2.5 px-3">{Number(r[3]) <= 0 ? "0 lb" : `${Number(r[3]).toFixed(1)} lb`}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free BMI Overweight Status Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">BMI is a screening tool, not a diagnosis. Age, gender, muscle mass, body composition, and medical history all matter.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/overweight-calculator" headingLevel="h3" /></main>
    </>
  );
}


